use soroban_sdk::{contract, contractimpl, contracttype, Address};

#[contracttype]
pub struct TestContract {
    pub admin: Address,
    pub unused_counter: u64,
}

#[contractimpl]
impl TestContract {
    pub fn new(admin: Address) -> Self {
        Self { admin, unused_counter: 0 }
    }

    pub fn get_admin(&self) -> Address {
        self.admin
    }
}
